// Verify Stripe webhook signature
const crypto = require('crypto');

const payload = $input.first().json.body;
const sig = $input.first().json.headers['stripe-signature'];
const secret = $env.STRIPE_WEBHOOK_SECRET;

if (!sig || !secret) {
  throw new Error('Missing Stripe signature or webhook secret');
}

// Parse the Stripe signature header
const elements = sig.split(',').reduce((acc, item) => {
  const [key, value] = item.split('=');
  acc[key] = value;
  return acc;
}, {});

const timestamp = elements['t'];
const signature = elements['v1'];

// Verify timestamp (reject events older than 5 minutes)
const tolerance = 300; // 5 minutes
const currentTime = Math.floor(Date.now() / 1000);
if (Math.abs(currentTime - parseInt(timestamp)) > tolerance) {
  throw new Error('Stripe webhook timestamp too old');
}

// Verify signature
const signedPayload = `${timestamp}.${typeof payload === 'string' ? payload : JSON.stringify(payload)}`;
const expectedSignature = crypto
  .createHmac('sha256', secret)
  .update(signedPayload)
  .digest('hex');

if (signature !== expectedSignature) {
  throw new Error('Invalid Stripe webhook signature');
}

const event = typeof payload === 'string' ? JSON.parse(payload) : payload;

return [{
  json: {
    event_id: event.id,
    event_type: event.type,
    data: event.data?.object || {},
    created: event.created
  }
}];

// Handle checkout.session.completed
const data = $input.first().json.data;

return [{
  json: {
    action: 'create_subscription',
    stripe_customer_id: data.customer,
    stripe_subscription_id: data.subscription,
    company_id: data.metadata?.company_id,
    plan_id: data.metadata?.plan_id,
    slack_message: `*New Subscription!* :tada:\nCompany: ${data.metadata?.company_name || 'Unknown'}\nPlan: ${data.metadata?.plan_id || 'Unknown'}\nAmount: $${(data.amount_total / 100).toFixed(2)}`
  }
}];

// Handle invoice.payment_succeeded
const data = $input.first().json.data;

return [{
  json: {
    action: 'log_payment',
    stripe_customer_id: data.customer,
    stripe_invoice_id: data.id,
    amount: data.amount_paid,
    currency: data.currency,
    period_start: data.period_start,
    period_end: data.period_end,
    slack_message: `*Payment Received*\nCustomer: ${data.customer_email || data.customer}\nAmount: $${(data.amount_paid / 100).toFixed(2)} ${data.currency?.toUpperCase()}`
  }
}];

// Handle invoice.payment_failed
const data = $input.first().json.data;

return [{
  json: {
    action: 'payment_failed',
    stripe_customer_id: data.customer,
    stripe_invoice_id: data.id,
    amount: data.amount_due,
    attempt_count: data.attempt_count,
    next_attempt: data.next_payment_attempt,
    slack_message: `*PAYMENT FAILED* :warning:\nCustomer: ${data.customer_email || data.customer}\nAmount: $${(data.amount_due / 100).toFixed(2)}\nAttempt: ${data.attempt_count}\nNext retry: ${data.next_payment_attempt ? new Date(data.next_payment_attempt * 1000).toISOString() : 'none'}`
  }
}];

// Handle customer.subscription.deleted
const data = $input.first().json.data;

return [{
  json: {
    action: 'cancel_subscription',
    stripe_customer_id: data.customer,
    stripe_subscription_id: data.id,
    canceled_at: data.canceled_at,
    slack_message: `*Subscription Canceled* :red_circle:\nCustomer: ${data.customer}\nPlan: ${data.plan?.id || 'unknown'}\nCanceled at: ${new Date((data.canceled_at || 0) * 1000).toISOString()}`
  }
}];
